INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '2. Ресурсы — ярость/энергия/мана + combo points ✅; руны/осколки НЕТ', 'Combo points', 'Разбойник, друид-кошка', '✅', '✅ (CP.1–CP.3b)');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '2. Ресурсы — ярость/энергия/мана + combo points ✅; руны/осколки НЕТ', 'Руны + runic power', 'DK', '✅', '✅ (RUNE.1–5)');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '2. Ресурсы — ярость/энергия/мана + combo points ✅; руны/осколки НЕТ', 'Осколки/камни души', 'Чернокнижник', '⬜', '⬜');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '3. Митигейшн / avoidance / absorb — РАЗОГНАЛИСЬ (блок/Глухая оборона)', 'MOD_BLOCK_PERCENT (51) + урон при блоке (43)', 'Блок щитом (Shield Block, Воин) ✅; Щит небес (Holy Shield 48952, Пал) ✅', '✅', '+30% блока — каркас `BlockBonus` (как у воина, лист 5%→35% **проверено**); ✅ BLOCK.2: при блоке урон Светом ~274 по атакующему (aura 43 PROC_TRIGGER_DAMAGE) — **проверено**. Todo: 8 зарядов (сейчас на всё время баффа)');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '3. Митигейшн / avoidance / absorb — РАЗОГНАЛИСЬ (блок/Глухая оборона)', 'MOD_DAMAGE_PERCENT_TAKEN (87)', 'Глухая оборона/Shield Wall −60% (Воин) ✅; Divine Protection −50% (Пал), Pain Suppression −40%/Dispersion −90% (Жрец), Barkskin −20% (Друид), Icebound Fortitude −30% (DK), Shamanistic Rage −30% (Шам)', '✅', '✅ все data-driven одним каркасом (aura 87, misc 127 = все школы; формула `dmg×max(0,1+pct/100)` в `ResolveIncomingMelee`) — **проверено вживую (смоук по классам)**. Применяется к мили-урону существ (спелл-урон существ не моделируется)');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '3. Митигейшн / avoidance / absorb — РАЗОГНАЛИСЬ (блок/Глухая оборона)', 'MOD_DODGE_PERCENT (49)', 'Evasion (Разб) ✅, Quickness-расовый ⬜', '✅', '✅ DODGE.1 (data-driven aura 49 → +% уклонения; резолвер мили-удара добавляет бонус к базовому dodge, обновляет PLAYER_DODGE_PERCENTAGE. Evasion 5277/26669 +50% 15с — **проверено вживую**: `.dummy attack` → свинги «Уклонение». Quickness — пассив-расовый на ауре 154, отдельно)');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '3. Митигейшн / avoidance / absorb — РАЗОГНАЛИСЬ (блок/Глухая оборона)', 'SCHOOL_ABSORB / MANA_SHIELD', 'PW:Shield (Жрец) ✅, Ice Barrier/Fire/Frost Ward (Маг) ✅, Mana Shield (Маг) ✅, Sacred Shield (Пал) ✅; Anti-Magic Shell (DK) ⬜', '✅', '✅ ABS.1–ABS.2 (поглощение мили существ по школе + absorb в damage-логе; Mana Shield тратит ману). ✅ ABS.3 Священный щит (Sacred Shield 53601, ≠ Holy Shield 48952): прок-поглощение ~500 на получение урона, ICD 6с — **проверено** (упрощённо: поглощаем мили-удар напрямую; визуал щита один раз на бафф). Todo: персист, поглощение спелл-урона существ');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '3. Митигейшн / avoidance / absorb — РАЗОГНАЛИСЬ (блок/Глухая оборона)', 'SCHOOL_IMMUNITY / DAMAGE_IMMUNITY (39/40)', 'Divine Shield (Пал) ✅, Ice Block (Маг) ✅, Hand of Protection (Пал) ✅', '✅', '✅ IMMUNITY.1 (data-driven по аурам 39/40: маска школ из всех таких эффектов; пока активна аура — входящий мили-урон совпадающей школы гасится в ноль, клиент «Иммунитет» VictimState=7 — **проверено**). + само-рут Ice Block («вмёрз в глыбу», SMSG_FORCE_MOVE_ROOT/UNROOT) — **проверено**. ✅ IMMUNITY.2 (Divine Shield −50% наносимого урона — aura 79, теперь и на автоатаке; **Forbearance** 25771: пузыри/Lay on Hands вешают дебафф 2 мин + гейт повторного каста SPELL_FAILED_CASTER_AURASTATE — **проверено**). Todo: иммунитет к спелл-урону существ, снятие свинга, untargetable/Divine Intervention, персист');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '4. CC (контроль) — фреймворк ЕСТЬ (`CrowdControlService`, data-driven по CC-ауре)', 'Stun', 'Hammer of Justice (Пал ✅), Concussion Blow (Воин), Cheap/Kidney Shot (Разб), Deep Freeze (Маг), Bash (Друид), Shadowfury (ЧК)', '✅', '✅ одиночная цель (HoJ + Seal of Justice проверены); AoE-стан ⬜');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '4. CC (контроль) — фреймворк ЕСТЬ (`CrowdControlService`, data-driven по CC-ауре)', 'Root', 'Frost Nova (Маг — AoE!), Entangling Roots (Друид), Freezing Trap (Охот), Chains of Ice (DK)', '🟡', '🟡 одиночная цель — визуал; AoE (Frost Nova) ⬜');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '4. CC (контроль) — фреймворк ЕСТЬ (`CrowdControlService`, data-driven по CC-ауре)', 'Fear', 'Psychic Scream (Жрец — AoE), Fear/Howl of Terror (ЧК), Intimidating Shout (Воин), Scare Beast (Охот)', '🟡', '🟡 одиночная цель (стопает + визуал); AoE/fleeing ⬜');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '4. CC (контроль) — фреймворк ЕСТЬ (`CrowdControlService`, data-driven по CC-ауре)', 'Silence', 'Strangulate (DK), Silencing Shot (Охот), Arcane Torrent (Эльф крови); Counterspell-lockout (Маг)', '🟡', '🟡 (визуал) / ⬜ (lockout)');
INSERT INTO project.Mechanics (phase, section, item, classes, status, note) VALUES ('Фаза 2 — механики по убыванию отдачи', '4. CC (контроль) — фреймворк ЕСТЬ (`CrowdControlService`, data-driven по CC-ауре)', 'Disorient/Poly', 'Polymorph (Маг ✅), Blind (Разб), Dragon''s Breath (Маг — AoE), Scatter Shot (Охот), Hibernate', '✅', '✅ одиночная цель (Polymorph проверен; стопает + визуал); break-on-damage ⬜');
